#[test]
fn render_summary_matches_page_summary() {
    use aureline_shell::system_browser_return_paths::SystemBrowserReturnPathsRenderSummary;
    let from_file: SystemBrowserReturnPathsRenderSummary = load("render_summary.json");
    let page: SystemBrowserReturnPathsBetaPage = load("page.json");
    let from_page = SystemBrowserReturnPathsRenderSummary::from_page(&page);
    assert_eq!(from_file, from_page);
}
